37: type Mailer interface {
38: 	Send(ctx context.Context, messages ...*Message) (int, error)
39: }
40: 
41: func (ns *NotificationService) Send(ctx context.Context, msg *Message) (int, error) {
42: 	messages := []*Message{}
43: 
44: 	if msg.SingleEmail {
45: 		messages = append(messages, msg)
46: 	} else {
47: 		for _, address := range msg.To {
48: 			copy := *msg
49: 			copy.To = []string{address}
50: 			messages = append(messages, &copy)
51: 		}
52: 	}
53: 
54: 	return ns.mailer.Send(ctx, messages...)
55: }
56: 
57: func (ns *NotificationService) buildEmailMessage(cmd *SendEmailCommand) (*Message, error) {
58: 	if !ns.Cfg.Smtp.Enabled {
59: 		return nil, ErrSmtpNotEnabled
60: 	}
61: 
62: 	data := cmd.Data
63: 	if data == nil {
64: 		data = make(map[string]any, 10)
65: 	}
66: 
67: 	setDefaultTemplateData(ns.Cfg, data, nil)
68: 
69: 	body := make(map[string]string)
70: 	for _, contentType := range ns.Cfg.Smtp.ContentTypes {
71: 		fileExtension, err := getFileExtensionByContentType(contentType)
72: 		if err != nil {
73: 			return nil, err
74: 		}
75: 		var buffer bytes.Buffer
76: 		err = mailTemplates.ExecuteTemplate(&buffer, cmd.Template+fileExtension, data)
77: 		if err != nil {
78: 			return nil, err
79: 		}
